import{_ as d,o as e,c as a,a2 as o}from"./chunks/framework.Wufm-cgV.js";const _=JSON.parse('{"title":"配置说明","description":"环境变量和系统设置参考","frontmatter":{"title":"配置说明","description":"环境变量和系统设置参考"},"headers":[],"relativePath":"zh/guide/configuration.md","filePath":"zh/guide/configuration.md"}'),r={name:"zh/guide/configuration.md"};function c(h,t,i,l,n,b){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="配置说明" tabindex="-1">配置说明 <a class="header-anchor" href="#配置说明" aria-label="Permalink to &quot;配置说明&quot;">​</a></h1><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h2><h3 id="核心设置" tabindex="-1">核心设置 <a class="header-anchor" href="#核心设置" aria-label="Permalink to &quot;核心设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SESSION_SECRET</code></td><td>Flask 会话密钥</td><td>自动生成</td></tr><tr><td><code>DATABASE_URI</code></td><td>数据库连接</td><td><code>sqlite:///data/webrouter.db</code></td></tr><tr><td><code>REDIS_URL</code></td><td>Redis 连接（可选，缓存用）</td><td><code>redis://localhost:6379/0</code></td></tr><tr><td><code>FLASK_ENV</code></td><td>运行环境</td><td><code>production</code></td></tr><tr><td><code>TZ</code></td><td>时区</td><td><code>Asia/Shanghai</code></td></tr></tbody></table><h3 id="端口配置" tabindex="-1">端口配置 <a class="header-anchor" href="#端口配置" aria-label="Permalink to &quot;端口配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>WR_PORT</code></td><td>Flask 管理面板端口</td><td><code>5050</code></td></tr><tr><td><code>WR_PROXY_PORT</code></td><td>wr-proxy 网关端口</td><td><code>5051</code></td></tr><tr><td><code>NEWAPI_URL</code></td><td>New-API sidecar 地址</td><td><code>http://localhost:3000</code></td></tr></tbody></table><h3 id="调度器" tabindex="-1">调度器 <a class="header-anchor" href="#调度器" aria-label="Permalink to &quot;调度器&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>ENABLE_SCHEDULER</code></td><td>Debug 模式强制启用调度器</td><td><code>0</code></td></tr><tr><td><code>HEALTH_CHECK_INTERVAL</code></td><td>健康检测间隔（秒）</td><td><code>300</code></td></tr><tr><td><code>BALANCE_CHECK_INTERVAL</code></td><td>余额检测间隔（秒）</td><td><code>1800</code></td></tr></tbody></table><h3 id="告警" tabindex="-1">告警 <a class="header-anchor" href="#告警" aria-label="Permalink to &quot;告警&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>ALERT_COOLDOWN</code></td><td>告警冷却时间（秒）</td><td><code>300</code></td></tr></tbody></table><h3 id="管理员账号" tabindex="-1">管理员账号 <a class="header-anchor" href="#管理员账号" aria-label="Permalink to &quot;管理员账号&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>WEBROUTER_ADMIN_USER</code></td><td>默认管理员用户名</td><td><code>admin</code></td></tr><tr><td><code>WEBROUTER_ADMIN_PASSWORD</code></td><td>默认管理员密码</td><td><code>admin123456</code></td></tr></tbody></table><h2 id="demo-模式" tabindex="-1">Demo 模式 <a class="header-anchor" href="#demo-模式" aria-label="Permalink to &quot;Demo 模式&quot;">​</a></h2><p>设置 <code>WEBROUTER_DEMO=1</code> 启用 Demo 模式：</p><ul><li>自动登录 demo/demo123456</li><li>核心数据只读保护</li><li>预置种子数据</li></ul>',15)])])}const u=d(r,[["render",c]]);export{_ as __pageData,u as default};
